from haystack import Pipeline
from haystack.components.builders import PromptBuilder

def scan_prompt_injection(pipeline: Pipeline):
    vulnerable = []
    for node_name, node in pipeline._nodes.items():
        if isinstance(node[1], PromptBuilder):
            template = node[1].template
            if '{' in template and '}' in template:
                # Check for unsafe variable interpolation
                if any(var in template for var in ['query', 'message', 'input']):
                    if not any(delimiter in template for delimiter in ['|||', '[INST]', '###')):
                        vulnerable.append({
                            'component': node_name,
                            'issue': 'Unsafe prompt template without delimiters',
                            'template': template
                        })
    return vulnerable

import re
from haystack.components.retrievers.in_memory import InMemoryEmbeddingRetriever

def detect_retriever_injection(retriever, test_payloads):
    injection_patterns = [
        r'ignore.*previous.*instructions',
        r'you are.*hacked',
        r'print\(system\(',
        r'rm\s+-rf',
        r'\$\(curl',
    ]

    results = []
    for payload in test_payloads:
        docs = retriever.run(query=payload)['documents']
        for doc in docs:
            content = doc.content.lower()
            for pattern in injection_patterns:
                if re.search(pattern, content):
                    results.append({
                        'payload': payload,
                        'document': doc.content,
                        'match': pattern
                    })
    return results

from haystack import Pipeline
from typing import Dict, Any

def audit_agent_inputs(pipeline: Pipeline):
    issues = []
    llm_nodes = ['llm', 'openai', 'gpt', 'generator']

    for node_name, (node, _) in pipeline._nodes.items():
        if any(llm_name in node_name.lower() for llm_name in llm_nodes):
            inputs = pipeline.get_inputs_for_node(node_name)
            for input_name, input_node in inputs.items():
                if 'user' in input_name.lower() or 'query' in input_name.lower():
                    # Check if there's sanitization between user input and LLM
                    path = pipeline._get_path(input_node[0], node_name)
                    sanitizers = ['sanitizer', 'validator', 'filter']
                    if not any(sanitizer in step for step in path for sanitizer in sanitizers):
                        issues.append({
                            'llm_node': node_name,
                            'unsanitized_input': input_name,
                            'path': path
                        })
    return issues

