from haystack import component

@component
class InjectionFilter:
    @component.output_types(documents=list)
    def run(self, documents: list):
        safe_docs = []
        injection_patterns = [
            r'ignore.*previous',
            r'you are.*hacked',
            r'print\(system',
            r'rm\s+-rf',
            r'\$\(curl',
        ]

        for doc in documents:
            content = doc.content.lower()
            if not any(re.search(p, content) for p in injection_patterns):
                safe_docs.append(doc)
        return {"documents": safe_docs}

# Pipeline integration
pipeline.add_component("injection_filter", InjectionFilter())
pipeline.connect("retriever.documents", "injection_filter.documents")
pipeline.connect("injection_filter.documents", "prompt_builder.documents")

from vex_sdk import VexGuard
from haystack import component

@component
class VexInjectionGuard:
    def __init__(self):
        self.vex = VexGuard()

    @component.output_types(prompt=str, safe=bool)
    def run(self, prompt: str, **kwargs):
        result = self.vex.scan_prompt(prompt, threat_model="prompt_injection")
        if result.is_safe:
            return {"prompt": result.cleaned_prompt, "safe": True}
        return {"prompt": "[INPUT BLOCKED: Potential injection detected]", "safe": False}

# Pipeline
pipeline.add_component("vex_guard", VexInjectionGuard())
pipeline.connect("prompt_builder.prompt", "vex_guard.prompt")
pipeline.connect("vex_guard.prompt", "llm.prompt")
